#!/usr/bin/env node

import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import path from "node:path";

export const EXIT_CODES = {
  success: 0,
  missingCredential: 41,
  contractViolation: 42,
  retryExhausted: 43,
  mutatingMethodRejected: 44
};

function parseArgs(argv) {
  const parsed = {
    configPath: path.resolve("release-feed.config.json")
  };

  for (let index = 0; index < argv.length; index += 1) {
    const token = argv[index];
    if (token === "--config") {
      parsed.configPath = path.resolve(argv[index + 1]);
      index += 1;
    }
  }

  return parsed;
}

function readJson(filePath) {
  return JSON.parse(readFileSync(filePath, "utf8"));
}

function writeNormalized(filePath, value) {
  mkdirSync(path.dirname(filePath), { recursive: true });
  writeFileSync(filePath, `${value.trimEnd()}\n`);
}

function parseRetryAfter(value) {
  if (!value) {
    return null;
  }

  const trimmed = value.trim();
  if (/^\d+$/.test(trimmed)) {
    return Number.parseInt(trimmed, 10);
  }

  const targetTime = Date.parse(trimmed);
  if (Number.isNaN(targetTime)) {
    return null;
  }

  return Math.max(0, Math.ceil((targetTime - Date.now()) / 1000));
}

function validateRelease(release) {
  const requiredFields = ["id", "tag", "title", "published_at", "summary_url", "notes"];
  for (const field of requiredFields) {
    if (typeof release?.[field] !== "string" || release[field].trim() === "") {
      return {
        ok: false,
        message: `release field missing: ${field}`
      };
    }
  }

  return { ok: true };
}

function validatePage(pageBody) {
  if (!pageBody || typeof pageBody !== "object") {
    return { ok: false, message: "page body must be an object" };
  }

  if (!Array.isArray(pageBody.releases)) {
    return { ok: false, message: "releases must be an array" };
  }

  if (pageBody.releases.length === 0) {
    return { ok: false, message: "empty releases are a contract failure" };
  }

  if (pageBody.next_page !== null && !Number.isInteger(pageBody.next_page)) {
    return { ok: false, message: "next_page must be an integer or null" };
  }

  for (const release of pageBody.releases) {
    const releaseValidation = validateRelease(release);
    if (!releaseValidation.ok) {
      return releaseValidation;
    }
  }

  return { ok: true };
}

function renderReleaseRows(releases) {
  return releases
    .map(
      (release) =>
        `- \`${release.tag}\` | ${release.title} | ${release.published_at} | ${release.summary_url}`
    )
    .join("\n");
}

function renderMarkdown(template, report) {
  const replacements = {
    "{{status}}": report.status,
    "{{release_count}}": String(report.release_count),
    "{{method}}": report.request_contract.method,
    "{{pagination}}": report.request_contract.pagination,
    "{{retry_429}}": String(report.evidence.retries.filter((entry) => entry.kind === "429").length),
    "{{retry_5xx}}": String(report.evidence.retries.filter((entry) => entry.kind === "5xx").length),
    "{{release_rows}}": renderReleaseRows(report.releases),
    "{{base_url_source}}": report.request_contract.base_url_source,
    "{{credential_source}}": report.request_contract.credential_source,
    "{{request_order}}": report.evidence.requests.map((entry) => entry.path).join(" -> "),
    "{{response_schema}}": report.request_contract.response_schema,
    "{{notes}}":
      "Evidence stores request paths, page order, statuses, and retry counts only; secret transport material stays redacted."
  };

  return Object.entries(replacements).reduce(
    (content, [placeholder, value]) => content.replaceAll(placeholder, value),
    template
  );
}

function failure(exitCode, status, message, evidence) {
  return {
    exitCode,
    summary: {
      status,
      exit_code: exitCode,
      message,
      request_count: evidence.requests.length,
      retry_count: evidence.retries.length,
      reports_written: false
    }
  };
}

export async function runReleaseFeed(options = {}) {
  const cwd = options.cwd || process.cwd();
  const env = options.env || process.env;
  const fetchImpl = options.fetchImpl || globalThis.fetch;
  const wait = options.wait || ((milliseconds) => new Promise((resolve) => setTimeout(resolve, milliseconds)));
  const configPath = options.configPath || path.join(cwd, "release-feed.config.json");
  const config = readJson(configPath);

  if (typeof fetchImpl !== "function") {
    throw new Error("global fetch is not available in this Node runtime");
  }

  const method = String(config.method || "GET").toUpperCase();
  const baseUrl = env[config.base_url_env];
  const credential = env[config.credential_env];
  const evidence = {
    requests: [],
    pages: [],
    retries: []
  };

  if (!credential) {
    return failure(
      EXIT_CODES.missingCredential,
      "missing_credential",
      `missing required credential env: ${config.credential_env}`,
      evidence
    );
  }

  if (method !== "GET") {
    return failure(
      EXIT_CODES.mutatingMethodRejected,
      "mutating_method_rejected",
      `configured method ${method} is not allowed for this read-only integration`,
      evidence
    );
  }

  const releases = [];
  let page = 1;

  while (page !== null) {
    let completed = false;
    let attempt = 0;
    while (!completed) {
      attempt += 1;
      const requestUrl = new URL(config.feed_path, baseUrl);
      requestUrl.searchParams.set(config.page_param, String(page));
      evidence.requests.push({
        sequence: evidence.requests.length + 1,
        method,
        path: `${requestUrl.pathname}${requestUrl.search}`,
        auth_present: true
      });

      const response = await fetchImpl(requestUrl, {
        method,
        headers: {
          accept: "application/json",
          authorization: `Bearer ${credential}`
        }
      });

      if (response.status === 429) {
        const retryAfterSeconds = parseRetryAfter(response.headers.get("retry-after"));
        evidence.retries.push({
          kind: "429",
          page,
          status: 429,
          attempt,
          retry_after_seconds: retryAfterSeconds
        });
        await wait(Math.max(0, retryAfterSeconds || 0) * 1000);
        continue;
      }

      if (response.status >= 500 && response.status <= 599) {
        evidence.retries.push({
          kind: "5xx",
          page,
          status: response.status,
          attempt
        });
        if (attempt > config.max_5xx_retries) {
          return failure(
            EXIT_CODES.retryExhausted,
            "retry_exhausted",
            `received ${response.status} after ${config.max_5xx_retries} retries`,
            evidence
          );
        }
        continue;
      }

      if (!response.ok) {
        return failure(
          EXIT_CODES.contractViolation,
          "unexpected_status",
          `unexpected status ${response.status}`,
          evidence
        );
      }

      const pageBody = await response.json();
      const validation = validatePage(pageBody);
      if (!validation.ok) {
        return failure(
          EXIT_CODES.contractViolation,
          "contract_violation",
          validation.message,
          evidence
        );
      }

      evidence.pages.push({
        page,

        status: response.status,
        release_count: pageBody.releases.length,
        next_page: pageBody.next_page
      });
      releases.push(...pageBody.releases);
      page = pageBody.next_page;
      completed = true;
    }
  }

  const report = {
    status: "success",
    generated_by: "release-feed-api-fixture",
    release_count: releases.length,
    releases,
    request_contract: {
      base_url_source: `env:${config.base_url_env}`,
      credential_source: `env:${config.credential_env}`,
      method,
      pagination: "serial",
      retry_policy: {
        respect_retry_after_on_429: true,
        max_5xx_retries: config.max_5xx_retries
      },
      response_schema: config.response_schema
    },
    evidence: {
      requests: evidence.requests.map((entry) => ({
        sequence: entry.sequence,
        method: entry.method,
        path: entry.path
      })),
      pages: evidence.pages,
      retries: evidence.retries,
      credential_material: "redacted"
    }
  };

  const jsonOutputPath = path.join(cwd, config.output_json);
  const markdownOutputPath = path.join(cwd, config.output_md);
  const templatePath = path.join(
    cwd,
    ".agents/skills/release-feed-api/assets/report-template.md"
  );
  const template = readFileSync(templatePath, "utf8");
  writeNormalized(jsonOutputPath, JSON.stringify(report, null, 2));
  writeNormalized(markdownOutputPath, renderMarkdown(template, report));

  return {
    exitCode: EXIT_CODES.success,
    summary: {
      status: "success",
      exit_code: 0,
      release_count: releases.length,
      report_json: config.output_json,
      report_markdown: config.output_md,
      request_count: evidence.requests.length,
      retry_count: evidence.retries.length,
      reports_written: true
    }
  };
}

if (import.meta.url === `file://${process.argv[1]}`) {
  const { configPath } = parseArgs(process.argv.slice(2));
  const result = await runReleaseFeed({ configPath });
  process.stdout.write(`${JSON.stringify(result.summary, null, 2)}\n`);
  process.exit(result.exitCode);
}

#!/usr/bin/env node

import { createServer } from "node:http";
import { randomUUID } from "node:crypto";

const successPages = {
  1: {
    releases: [
      {
        id: "release-240",
        tag: "v2.4.0",
        title: "Release Feed API",
        published_at: "2026-07-01",
        summary_url: "/notes/v2.4.0",
        notes: "Adds explicit request contract guards."
      },
      {
        id: "release-231",
        tag: "v2.3.1",
        title: "Rate Limit Retry",
        published_at: "2026-06-22",
        summary_url: "/notes/v2.3.1",
        notes: "Documents Retry-After handling."
      }
    ],
    next_page: 2
  },
  2: {
    releases: [
      {
        id: "release-230",
        tag: "v2.3.0",
        title: "Schema Validation",
        published_at: "2026-06-12",
        summary_url: "/notes/v2.3.0",
        notes: "Rejects empty payloads as contract drift."
      }
    ],
    next_page: null
  }
};

function json(response, statusCode, payload, headers = {}) {
  response.writeHead(statusCode, {
    "content-type": "application/json; charset=utf-8",
    ...headers
  });
  response.end(`${JSON.stringify(payload)}\n`);
}

function pagePath(requestUrl) {
  return `${requestUrl.pathname}${requestUrl.search}`;
}

function createHandler(scenario, credential, state) {
  return ({ method, url, headers }) => {
    const requestUrl = typeof url === "string" ? new URL(url) : url;
    const authorization = headers.authorization || headers.Authorization;
    const page = Number.parseInt(requestUrl.searchParams.get("page") || "1", 10);
    state.requests.push({
      method,
      path: pagePath(requestUrl),
      auth_present: Boolean(authorization)
    });

    if (method !== "GET") {
      return {
        status: 405,
        payload: { error: "method_not_allowed" },
        headers: {}
      };
    }

    if (authorization !== `Bearer ${credential}`) {
      return {
        status: 401,
        payload: { error: "missing_or_invalid_credential" },
        headers: {}
      };
    }

    if (scenario === "rate-limit-once" && state.rate_limit_hits === 0 && page === 1) {
      state.rate_limit_hits += 1;
      return {
        status: 429,
        payload: { error: "too_many_requests", retry_after: 0 },
        headers: { "retry-after": "0" }
      };
    }

    if (scenario === "retry-exhausted") {
      return {
        status: 503,
        payload: { error: "upstream_unavailable" },
        headers: {}
      };
    }

    if (scenario === "schema-drift") {
      return {
        status: 200,
        payload: {
          releases: [
            {
              id: "release-240",
              tag: "v2.4.0",
              title: "Broken Release Contract",
              summary_url: "/notes/v2.4.0",
              notes: "published_at was removed"
            }
          ],
          next_page: null
        },
        headers: {}
      };
    }

    const payload = successPages[page];
    if (!payload) {
      return {
        status: 404,
        payload: { error: "page_not_found" },
        headers: {}
      };
    }

    return {
      status: 200,
      payload,
      headers: {}
    };
  };
}

export function createMockFetchTransport(options = {}) {
  const scenario = options.scenario || "two-page-success";
  const credential = options.credential || randomUUID();
  const state = {
    scenario,
    credential_required: true,
    rate_limit_hits: 0,
    requests: []
  };
  const handler = createHandler(scenario, credential, state);

  return {
    credential,
    state,
    async fetch(url, requestOptions = {}) {
      const headers = requestOptions.headers || {};
      const result = handler({
        method: requestOptions.method || "GET",
        url,
        headers
      });
      return {
        ok: result.status >= 200 && result.status < 300,
        status: result.status,
        headers: {
          get(name) {
            const exact = result.headers[name];
            if (exact) {
              return exact;
            }
            return result.headers[name.toLowerCase()] || null;
          }
        },
        async json() {
          return result.payload;
        }
      };
    }
  };
}

export async function startMockReleaseApi(options = {}) {
  const scenario = options.scenario || "two-page-success";
  const credential = options.credential || randomUUID();
  const state = {
    scenario,
    credential_required: true,
    rate_limit_hits: 0,
    requests: []
  };
  const handler = createHandler(scenario, credential, state);
  const server = createServer((request, response) => {
    const result = handler({
      method: request.method,
      url: new URL(request.url, "http://127.0.0.1"),
      headers: request.headers
    });
    json(response, result.status, result.payload, result.headers);
  });

  await new Promise((resolve, reject) => {
    server.once("error", reject);
    server.listen(0, "127.0.0.1", () => {
      server.off("error", reject);
      resolve();
    });
  });

  const address = server.address();
  const baseUrl = `http://127.0.0.1:${address.port}`;

  return {
    baseUrl,
    credential,
    state,
    close() {
      return new Promise((resolve, reject) => {
        server.close((error) => {
          if (error) {
            reject(error);
            return;
          }
          resolve();
        });
      });
    }
  };
}

if (import.meta.url === `file://${process.argv[1]}`) {
  const scenario = process.argv[2] || "two-page-success";
  const credential = process.env.RELEASE_FEED_TOKEN || randomUUID();
  const server = await startMockReleaseApi({ scenario, credential });
  process.stdout.write(
    `${JSON.stringify(
      {
        scenario,
        base_url: server.baseUrl,
        credential_source: "env:RELEASE_FEED_TOKEN"
      },
      null,
      2
    )}\n`
  );
}

import assert from "node:assert/strict";
import { cpSync, mkdtempSync, readFileSync, rmSync, writeFileSync } from "node:fs";
import os from "node:os";
import path from "node:path";
import test from "node:test";
import { randomUUID } from "node:crypto";
import { fileURLToPath } from "node:url";
import {
  EXIT_CODES,
  runReleaseFeed
} from "../.agents/skills/release-feed-api/scripts/fetch-releases.mjs";
import {
  createMockFetchTransport,
  startMockReleaseApi
} from "../.agents/skills/release-feed-api/scripts/mock-release-api.mjs";

const fixtureRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");

function createTempRepo() {
  const tempRoot = mkdtempSync(path.join(os.tmpdir(), "release-feed-api-test-"));
  cpSync(fixtureRoot, tempRoot, { recursive: true });
  return tempRoot;
}

function cleanup(directory) {
  rmSync(directory, { recursive: true, force: true });
}

async function withTransport(scenario, callback) {
  const transport = createMockFetchTransport({
    scenario,
    credential: randomUUID()
  });
  return callback(transport);
}

test("two-page success writes redacted reports", async () => {
  await withTransport("two-page-success", async (server) => {
    const tempRepo = createTempRepo();
    try {
      const result = await runReleaseFeed({
        cwd: tempRepo,
        env: {
          ...process.env,
          RELEASE_FEED_BASE_URL: "http://127.0.0.1:<loopback-port>",
          RELEASE_FEED_TOKEN: server.credential
        },
        fetchImpl: server.fetch,
        wait: async () => {}
      });

      assert.equal(result.exitCode, EXIT_CODES.success);
      const reportJson = readFileSync(path.join(tempRepo, "reports/releases.json"), "utf8");
      const reportMarkdown = readFileSync(path.join(tempRepo, "reports/releases.md"), "utf8");
      const parsed = JSON.parse(reportJson);

      assert.equal(parsed.release_count, 3);
      assert.deepEqual(
        parsed.evidence.requests.map((entry) => entry.path),
        ["/releases?page=1", "/releases?page=2"]
      );
      assert.equal(server.state.requests.length, 2);
      assert.equal(reportJson.includes(server.credential), false);
      assert.equal(reportMarkdown.includes(server.credential), false);
      assert.equal(/authorization/i.test(reportJson), false);
      assert.equal(/authorization/i.test(reportMarkdown), false);
    } finally {
      cleanup(tempRepo);
    }
  });
});

test("429 once then success records one retry", async () => {
  await withTransport("rate-limit-once", async (server) => {
    const tempRepo = createTempRepo();
    try {
      const result = await runReleaseFeed({
        cwd: tempRepo,
        env: {
          ...process.env,
          RELEASE_FEED_BASE_URL: "http://127.0.0.1:<loopback-port>",
          RELEASE_FEED_TOKEN: server.credential
        },
        fetchImpl: server.fetch,
        wait: async () => {}
      });

      assert.equal(result.exitCode, EXIT_CODES.success);
      const parsed = JSON.parse(readFileSync(path.join(tempRepo, "reports/releases.json"), "utf8"));
      assert.equal(parsed.evidence.retries.length, 1);
      assert.equal(parsed.evidence.retries[0].status, 429);
      assert.deepEqual(
        parsed.evidence.requests.map((entry) => entry.path),
        ["/releases?page=1", "/releases?page=1", "/releases?page=2"]
      );
      assert.equal(server.state.requests.length, 3);
    } finally {
      cleanup(tempRepo);
    }
  });
});

test("missing credential exits 41 before network", async () => {
  await withTransport("two-page-success", async (server) => {
    const tempRepo = createTempRepo();
    try {
      const result = await runReleaseFeed({
        cwd: tempRepo,
        env: {
          ...process.env,
          RELEASE_FEED_BASE_URL: "http://127.0.0.1:<loopback-port>",
          RELEASE_FEED_TOKEN: ""
        },
        fetchImpl: server.fetch,
        wait: async () => {}
      });

      assert.equal(result.exitCode, EXIT_CODES.missingCredential);
      assert.equal(server.state.requests.length, 0);
    } finally {
      cleanup(tempRepo);
    }
  });
});

test("schema drift exits 42", async () => {
  await withTransport("schema-drift", async (server) => {
    const tempRepo = createTempRepo();
    try {
      const result = await runReleaseFeed({
        cwd: tempRepo,
        env: {
          ...process.env,
          RELEASE_FEED_BASE_URL: "http://127.0.0.1:<loopback-port>",
          RELEASE_FEED_TOKEN: server.credential
        },
        fetchImpl: server.fetch,
        wait: async () => {}
      });

      assert.equal(result.exitCode, EXIT_CODES.contractViolation);
      assert.equal(server.state.requests.length, 1);
    } finally {
      cleanup(tempRepo);
    }
  });
});

test("503 retry exhausted exits 43", async () => {
  await withTransport("retry-exhausted", async (server) => {
    const tempRepo = createTempRepo();
    try {
      const result = await runReleaseFeed({
        cwd: tempRepo,
        env: {
          ...process.env,
          RELEASE_FEED_BASE_URL: "http://127.0.0.1:<loopback-port>",
          RELEASE_FEED_TOKEN: server.credential
        },
        fetchImpl: server.fetch,
        wait: async () => {}
      });

      assert.equal(result.exitCode, EXIT_CODES.retryExhausted);
      assert.equal(server.state.requests.length, 3);
    } finally {
      cleanup(tempRepo);
    }
  });
});

test("mutating method is rejected before network", async () => {
  await withTransport("two-page-success", async (server) => {
    const tempRepo = createTempRepo();
    try {
      const configPath = path.join(tempRepo, "release-feed.config.json");
      const config = JSON.parse(readFileSync(configPath, "utf8"));
      config.method = "POST";
      writeFileSync(configPath, `${JSON.stringify(config, null, 2)}\n`);

      const result = await runReleaseFeed({
        cwd: tempRepo,
        env: {
          ...process.env,
          RELEASE_FEED_BASE_URL: "http://127.0.0.1:<loopback-port>",
          RELEASE_FEED_TOKEN: server.credential
        },
        fetchImpl: server.fetch,
        wait: async () => {}
      });

      assert.equal(result.exitCode, EXIT_CODES.mutatingMethodRejected);
      assert.equal(server.state.requests.length, 0);
    } finally {
      cleanup(tempRepo);
    }
  });
});

test("loopback preflight is either available or explicitly blocked by the host", async () => {
  let server;
  try {
    server = await startMockReleaseApi({
      scenario: "two-page-success",
      credential: randomUUID()
    });
  } catch (error) {
    assert.equal(error?.code, "EPERM");
    return;
  }

  await server.close();
  assert.match(server.baseUrl, /^http:\/\/127\.0\.0\.1:\d+$/);
});
